// This is a Prisma schema file.
// Learn more: https://pris.ly/d/prisma-schema

datasource db {
  provider = "sqlite"
}

generator client {
  provider = "prisma-client-js"
}

model Bead {
  id        Int      @id @default(autoincrement())
  name      String
  nameRu    String
  shape     String   // "sphere" | "disc" | "star" | "heart" | "cylinder" — mapped in app
  size      Float
  material  String   // "wood" | "silicone" | "knit" | "plastic" — mapped in app
  color     String
  createdAt DateTime @default(now())
}

model Template {
  id              Int      @id @default(autoincrement())
  name            String
  designCode      String   @unique
  beadCount       Int
  isApproved      Boolean  @default(true)
  isUserSubmitted Boolean  @default(false)
  createdAt       DateTime @default(now())
}

model Order {
  id          Int      @id @default(autoincrement())
  designCode  String   @unique
  designState String   // JSON string of SerializableDesign
  status      String   @default("new")  // "new" | "processing" | "completed"
  beadCount   Int
  createdAt   DateTime @default(now())
}

@import "tailwindcss";

html {
  overflow: hidden;
  touch-action: none;
}

body {
  margin: 0;
  overflow: hidden;
  touch-action: none;
}

.canvas-container {
  touch-action: none;
}

/* R3F/Three.js sets touch-action: auto inline on the <canvas> element.
   !important is needed to override that inline style so the browser
   does not intercept touch events for scroll/zoom on the 3D canvas. */
.canvas-container canvas {
  touch-action: none !important;
}

/* Catalog bead grid: allow vertical pan scrolling inside the catalog panel.
   The global touch-action: none on html/body blocks all scrolling — this
   class overrides it for the catalog's scrollable bead grid. */
.catalog-scroll {
  touch-action: pan-y;
  -webkit-overflow-scrolling: touch;
}

/* Home page: the template gallery needs normal scrolling behaviour.
   The global touch-action: none and overflow: hidden are for the 3D canvas
   editor and must be overridden here. */
.home-page-root {
  overflow: auto;
  touch-action: auto;
  -webkit-overflow-scrolling: touch;
}

.home-page-root::-webkit-scrollbar {
  display: none;
}

/* Hide scrollbar on horizontal-scroll template gallery */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

import type { Metadata, Viewport } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "Bead Designer",
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  maximumScale: 1,
  userScalable: false,
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="ru">
      <body>{children}</body>
    </html>
  );
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { designCode, beadCount } = body;

    if (!designCode || !beadCount) {
      return NextResponse.json(
        { error: "designCode and beadCount are required" },
        { status: 400 }
      );
    }

    const order = await prisma.order.create({
      data: {
        designCode,
        designState: JSON.stringify({ designCode, beadCount }),
        status: "new",
        beadCount: Number(beadCount),
      },
    });

    return NextResponse.json(order, { status: 201 });
  } catch (error) {
    console.error("Failed to create order:", error);
    return NextResponse.json(
      { error: "Failed to create order" },
      { status: 500 }
    );
  }
}

export async function GET() {
  try {
    const orders = await prisma.order.findMany({
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json(orders);
  } catch (error) {
    console.error("Failed to fetch orders:", error);
    return NextResponse.json(
      { error: "Failed to fetch orders" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const templates = await prisma.template.findMany({
    where: { isApproved: true },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(templates);
}

import { PrismaClient } from "@prisma/client";
import { PrismaLibSql } from "@prisma/adapter-libsql";

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient };

function createPrismaClient() {
  const adapter = new PrismaLibSql({
    url: process.env.DATABASE_URL!,
  });
  return new PrismaClient({ adapter });
}

export const prisma = globalForPrisma.prisma || createPrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET(
  _req: Request,
  { params }: { params: Promise<{ code: string }> }
) {
  const { code } = await params;

  const template = await prisma.template.findUnique({
    where: { designCode: code },
  });

  if (!template) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  return NextResponse.json(template);
}

export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";
export type BeadShape = "sphere" | "disc" | "star" | "heart" | "cylinder";

export interface CatalogBead {
  id: string;
  name: string;
  nameRu: string;
  shape: BeadShape;
  size: number;
  material: BeadType;
  color: string;
  secondaryColor?: string;
}

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
  catalogBeadId?: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

/** Wire format for design serialization (JSON → LZ-String → base64url). */
export interface SerializableDesign {
  v: 1;
  p: "pacifier-holder";
  b: string[]; // catalogBeadId strings
}

